#!/usr/bin/env python3
"""Generate comprehensive first-division football team database as SQL + JSON."""
import json, re, unicodedata

def slugify(name, cc):
    s = unicodedata.normalize('NFD', name.lower())
    s = ''.join(c for c in s if unicodedata.category(c) != 'Mn')
    s = re.sub(r'[^a-z0-9\s-]', '', s).strip()
    s = re.sub(r'\s+', '-', s)
    s = re.sub(r'-+', '-', s)
    return f"{cc.lower()}-{s}"

def esc(s): return s.replace("'", "''")

# Format: (country, cc, league): [(name, short, [aliases])]
L = {}
def add(country, cc, league, teams):
    L[(country, cc, league)] = teams

