# Remove empty entries
L = {k: v for k, v in L.items() if len(v) > 0}

# Generate output
sql_lines = ["BEGIN;", ""]
json_teams = []
total = 0

for (country, cc, league), tlist in L.items():
    sql_lines.append(f"-- {country} ({cc}) - {league} ({len(tlist)} teams)")
    for (name, short, aliases) in tlist:
        tid = slugify(name, cc)
        search = list(set(aliases + [short]))
        search_pg = '{' + ','.join(f'"{a}"' for a in search) + '}'
        sql_lines.append(
            f"INSERT INTO public.teams (id, name, short_name, country, country_code, league_name, search_terms, is_active, updated_at) "
            f"VALUES ('{tid}', '{esc(name)}', '{short}', '{esc(country)}', '{cc}', '{esc(league)}', '{search_pg}', true, now()) "
            f"ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, short_name=EXCLUDED.short_name, country=EXCLUDED.country, "
            f"country_code=EXCLUDED.country_code, league_name=EXCLUDED.league_name, search_terms=EXCLUDED.search_terms, "
            f"is_active=true, updated_at=now();"
        )
        json_teams.append({
            "id": tid, "name": name, "short_name": short,
            "country": country, "country_code": cc, "league_name": league,
            "search_terms": search, "crest_url": None, "is_active": True,
        })
        total += 1
    sql_lines.append("")

sql_lines.append("COMMIT;")
sql_lines.append(f"-- Total teams seeded: {total}")

sql_path = "/Volumes/PRO-G40/FANZONE/supabase/migrations/20260420090000_seed_global_teams.sql"
with open(sql_path, 'w') as f:
    f.write('\n'.join(sql_lines))
print(f"SQL: {sql_path} ({total} teams)")

json_path = "/Volumes/PRO-G40/FANZONE/assets/data/team_search_database.json"
with open(json_path, 'w') as f:
    json.dump({"teams": json_teams, "count": total}, f, indent=2, ensure_ascii=False)
print(f"JSON: {json_path} ({total} teams)")

countries = set(cc for (_, cc, _) in L.keys())
print(f"\nSummary: {len(countries)} countries, {len(L)} leagues, {total} teams")
